(window.webpackJsonp=window.webpackJsonp||[]).push([[1034],{975:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> removeDuplicates = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n    nums.unshift(<span class=\\"hljs-literal\\">null</span>)\\n    <span class=\\"hljs-keyword\\">let</span> last=<span class=\\"hljs-literal\\">null</span>\\n    <span class=\\"hljs-keyword\\">let</span> idx=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;nums.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(nums[i]==last)<span class=\\"hljs-keyword\\">continue</span>\\n        nums[idx++]=nums[i]\\n        last=nums[i]\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> idx\\n};\\n</code></pre>\\n"],"titleSlug":"remove-duplicates-from-sorted-array","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u5bf9<code>nums</code>\u8fdb\u884c\u539f\u5730\u91cd\u6392\u5e8f\uff0c\u8bbe\u5b9a\u4e00\u4e2a\u7d22\u5f15<code>k</code>\uff0c\u8868\u793a\u5f53\u524d\u9700\u8981\u6539\u53d8\u7684\u4f4d\u7f6e\uff0c\u4ece<code>k=0</code>\u5f00\u59cb\uff0c\u5982\u679c\u53d1\u73b0\u6709\u6548(\u4e0d\u91cd\u590d)\uff0c\u5219<code>nums[k++]=nums[i]</code>\u3002</p>\\n<p>\u6700\u7ec8\u524d<code>k</code>\u4f4d\u7684\u90fd\u662f\u65e0\u91cd\u590d\u7684\u6570\u5b57\u3002</p>\\n","content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6709\u5e8f\u6570\u7ec4 <code>nums</code> \uff0c\u8bf7\u4f60<strong><a href=\\"http://baike.baidu.com/item/%E5%8E%9F%E5%9C%B0%E7%AE%97%E6%B3%95\\" target=\\"_blank\\"> \u539f\u5730</a></strong> \u5220\u9664\u91cd\u590d\u51fa\u73b0\u7684\u5143\u7d20\uff0c\u4f7f\u6bcf\u4e2a\u5143\u7d20 <strong>\u53ea\u51fa\u73b0\u4e00\u6b21</strong> \uff0c\u8fd4\u56de\u5220\u9664\u540e\u6570\u7ec4\u7684\u65b0\u957f\u5ea6\u3002</p>\\n\\n<p>\u4e0d\u8981\u4f7f\u7528\u989d\u5916\u7684\u6570\u7ec4\u7a7a\u95f4\uff0c\u4f60\u5fc5\u987b\u5728 <strong><a href=\\"https://baike.baidu.com/item/%E5%8E%9F%E5%9C%B0%E7%AE%97%E6%B3%95\\" target=\\"_blank\\">\u539f\u5730 </a>\u4fee\u6539\u8f93\u5165\u6570\u7ec4 </strong>\u5e76\u5728\u4f7f\u7528 O(1) \u989d\u5916\u7a7a\u95f4\u7684\u6761\u4ef6\u4e0b\u5b8c\u6210\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8bf4\u660e:</strong></p>\\n\\n<p>\u4e3a\u4ec0\u4e48\u8fd4\u56de\u6570\u503c\u662f\u6574\u6570\uff0c\u4f46\u8f93\u51fa\u7684\u7b54\u6848\u662f\u6570\u7ec4\u5462?</p>\\n\\n<p>\u8bf7\u6ce8\u610f\uff0c\u8f93\u5165\u6570\u7ec4\u662f\u4ee5<strong>\u300c\u5f15\u7528\u300d</strong>\u65b9\u5f0f\u4f20\u9012\u7684\uff0c\u8fd9\u610f\u5473\u7740\u5728\u51fd\u6570\u91cc\u4fee\u6539\u8f93\u5165\u6570\u7ec4\u5bf9\u4e8e\u8c03\u7528\u8005\u662f\u53ef\u89c1\u7684\u3002</p>\\n\\n<p>\u4f60\u53ef\u4ee5\u60f3\u8c61\u5185\u90e8\u64cd\u4f5c\u5982\u4e0b:</p>\\n\\n<pre>\\n// <strong>nums</strong> \u662f\u4ee5\u201c\u5f15\u7528\u201d\u65b9\u5f0f\u4f20\u9012\u7684\u3002\u4e5f\u5c31\u662f\u8bf4\uff0c\u4e0d\u5bf9\u5b9e\u53c2\u505a\u4efb\u4f55\u62f7\u8d1d\\nint len = removeDuplicates(nums);\\n\\n// \u5728\u51fd\u6570\u91cc\u4fee\u6539\u8f93\u5165\u6570\u7ec4\u5bf9\u4e8e\u8c03\u7528\u8005\u662f\u53ef\u89c1\u7684\u3002\\n// \u6839\u636e\u4f60\u7684\u51fd\u6570\u8fd4\u56de\u7684\u957f\u5ea6, \u5b83\u4f1a\u6253\u5370\u51fa\u6570\u7ec4\u4e2d<strong> \u8be5\u957f\u5ea6\u8303\u56f4\u5185</strong> \u7684\u6240\u6709\u5143\u7d20\u3002\\nfor (int i = 0; i < len; i++) {\\n\xa0 \xa0 print(nums[i]);\\n}\\n</pre>\\n\xa0\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [1,1,2]\\n<strong>\u8f93\u51fa\uff1a</strong>2, nums = [1,2]\\n<strong>\u89e3\u91ca\uff1a</strong>\u51fd\u6570\u5e94\u8be5\u8fd4\u56de\u65b0\u7684\u957f\u5ea6 <strong><code>2</code></strong> \uff0c\u5e76\u4e14\u539f\u6570\u7ec4 <em>nums </em>\u7684\u524d\u4e24\u4e2a\u5143\u7d20\u88ab\u4fee\u6539\u4e3a <strong><code>1</code></strong>, <strong><code>2 </code></strong><code>\u3002</code>\u4e0d\u9700\u8981\u8003\u8651\u6570\u7ec4\u4e2d\u8d85\u51fa\u65b0\u957f\u5ea6\u540e\u9762\u7684\u5143\u7d20\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [0,0,1,1,1,2,2,3,3,4]\\n<strong>\u8f93\u51fa\uff1a</strong>5, nums = [0,1,2,3,4]\\n<strong>\u89e3\u91ca\uff1a</strong>\u51fd\u6570\u5e94\u8be5\u8fd4\u56de\u65b0\u7684\u957f\u5ea6 <strong><code>5</code></strong> \uff0c \u5e76\u4e14\u539f\u6570\u7ec4 <em>nums </em>\u7684\u524d\u4e94\u4e2a\u5143\u7d20\u88ab\u4fee\u6539\u4e3a <strong><code>0</code></strong>, <strong><code>1</code></strong>, <strong><code>2</code></strong>, <strong><code>3</code></strong>, <strong><code>4</code></strong> \u3002\u4e0d\u9700\u8981\u8003\u8651\u6570\u7ec4\u4e2d\u8d85\u51fa\u65b0\u957f\u5ea6\u540e\u9762\u7684\u5143\u7d20\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>0 <= nums.length <= 3 * 10<sup>4</sup></code></li>\\n\\t<li><code>-10<sup>4</sup> <= nums[i] <= 10<sup>4</sup></code></li>\\n\\t<li><code>nums</code> \u5df2\u6309\u5347\u5e8f\u6392\u5217</li>\\n</ul>\\n\\n<p>\xa0</p>\\n","title":"26. \u5220\u9664\u6709\u5e8f\u6570\u7ec4\u4e2d\u7684\u91cd\u590d\u9879","relatedTags":["\u6570\u7ec4","\u53cc\u6307\u9488"],"difficult":"Easy","lang":["javascript"],"uniqueID":"26"}')}}]);